// ---- GENERATION ----

function gameMinute(gs) {
  if (!gs?.time) return 0;
  return (gs.stats?.daysElapsed || 0) * 1440 + gs.time.hour * 60 + gs.time.minute;
}

const GENERATORS = [
  { type: StationMissionType.CARGO_HAUL,               weight: 4, needsDest: true },
  { type: StationMissionType.PASSENGER_TRANSPORT,       weight: 3, needsDest: true },
  { type: StationMissionType.FUEL_RESUPPLY,             weight: 2, needsDest: true },
  { type: StationMissionType.INVESTIGATE_DISAPPEARANCE, weight: 2, needsDest: false },
  { type: StationMissionType.SALVAGE,                   weight: 3, needsDest: false },
  { type: StationMissionType.SURVEY,                    weight: 3, needsDest: false },
  { type: StationMissionType.MEDICAL_EVAC,              weight: 2, needsDest: false },
];

function pickWeightedType(generators) {
  const total = generators.reduce((s, g) => s + g.weight, 0);
  let r = Math.random() * total;
  for (const g of generators) {
    r -= g.weight;
    if (r <= 0) return g;
  }
  return generators[generators.length - 1];
}

/**
 * Generate missions for a station's board.
 * @param {object} station - station entity
 * @param {object[]} allStations - all station entities (for destination selection)
 * @param {object} gameState
 */
export function generateStationMissions(station, allStations, gameState) {
  const board = station._missionBoard;
  if (!board) return;

  // Don't overfill
  const slotsAvailable = board.maxMissions - board.missions.length;
  if (slotsAvailable <= 0) return;

  // Other stations as possible destinations (exclude self)
  const destinations = allStations.filter(s => s.id !== station.id);

  const count = randInt(Math.min(2, slotsAvailable), slotsAvailable);
  for (let i = 0; i < count; i++) {
    // Pick a type — if we have no other stations, skip destination-requiring types
    const available = destinations.length > 0
      ? GENERATORS
      : GENERATORS.filter(g => !g.needsDest);
    const gen = pickWeightedType(available);

    let mission;
    switch (gen.type) {
      case StationMissionType.CARGO_HAUL:
        mission = generateCargoHaul(station, destinations, gameState); break;
      case StationMissionType.PASSENGER_TRANSPORT:
        mission = generatePassengerTransport(station, destinations, gameState); break;
      case StationMissionType.FUEL_RESUPPLY:
        mission = generateFuelResupply(station, destinations, gameState); break;
      case StationMissionType.INVESTIGATE_DISAPPEARANCE:
        mission = generateInvestigation(station, gameState); break;
      case StationMissionType.SALVAGE:
        mission = generateSalvage(station, gameState); break;
      case StationMissionType.SURVEY:
        mission = generateSurvey(station, gameState); break;
      case StationMissionType.MEDICAL_EVAC:
        mission = generateMedicalEvac(station, gameState); break;
    }
    if (mission) board.missions.push(mission);
  }

  board.lastRefresh = gameMinute(gameState);
}

// ---- BOARD REFRESH ----

/**
 * Check all stations in range — refresh boards, expire old missions.
 * Called from missionTick every game-minute.
 */
export function stationMissionTick(gameState) {
  const entities = gameState.entities || [];
  const stations = entities.filter(e => e.type === 'station' && e._missionBoard);
  const shipPos = gameState.shipPosition;
  const now = gameMinute(gameState);
  const allStations = stations;
  const events = [];

  for (const station of stations) {
    const board = station._missionBoard;
    const dist = entityDistanceAU(shipPos, station.position);

    // Only refresh boards for stations within LONG scanner range
    if (dist > LONG_SCANNER_RANGE_AU) continue;

    // Expire old available missions
    board.missions = board.missions.filter(m => {
      if (m.phase !== MissionPhase.AVAILABLE) return true; // active missions don't expire from board
      const age = now - m.offeredAt;
      return age < m.expiresIn;
    });

    // Refresh if stale
    if (now - board.lastRefresh >= board.refreshInterval || board.missions.length === 0) {
      generateStationMissions(station, allStations, gameState);
    }
  }

  // Tick active station missions
  for (const mission of activeMissions) {
    if (mission.phase === MissionPhase.COMPLETE || mission.phase === MissionPhase.FAILED || mission.phase === MissionPhase.EXPIRED) continue;

    // Decrement urgency
    mission.urgencyTimerMin--;
    if (mission.urgencyTimerMin <= 0) {
      mission.phase = MissionPhase.FAILED;
      events.push({ type: 'station-mission-failed', mission, reason: 'Deadline expired' });
      continue;
    }

    // Phase transitions
    const phaseEvent = checkMissionPhase(mission, gameState);
    if (phaseEvent) events.push(phaseEvent);
  }

  return events;
}

// ---- PHASE TRANSITION LOGIC ----

function checkMissionPhase(mission, gameState) {
  const shipPos = gameState.shipPosition;

  switch (mission.type) {
    case StationMissionType.CARGO_HAUL:
    case StationMissionType.PASSENGER_TRANSPORT:
    case StationMissionType.FUEL_RESUPPLY: {
      // Delivery missions: accepted → check if near destination
      if (mission.phase === MissionPhase.ACCEPTED || mission.phase === MissionPhase.IN_TRANSIT) {
        const dest = (gameState.entities || []).find(e => e.id === mission.destination);
        if (dest) {
          const dist = entityDistanceAU(shipPos, dest.position);
          if (dist <= LONG_SCANNER_RANGE_AU) {
            mission.phase = MissionPhase.AT_OBJECTIVE;
            return { type: 'station-mission-phase', mission, phase: MissionPhase.AT_OBJECTIVE,
              message: `Approaching ${mission.destinationName} — hail to deliver` };
          }
        }
        mission.phase = MissionPhase.IN_TRANSIT;
      }
      break;
    }

    case StationMissionType.INVESTIGATE_DISAPPEARANCE:
    case StationMissionType.SALVAGE:
    case StationMissionType.MEDICAL_EVAC: {
      // Go-to-position missions: check if near target position
      if (mission.phase === MissionPhase.ACCEPTED || mission.phase === MissionPhase.IN_TRANSIT) {
        if (mission.targetPosition) {
          const dx = shipPos.x - mission.targetPosition.x;
          const dy = shipPos.y - mission.targetPosition.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          // Within SHORT scanner range (~150k km) = at objective
          if (dist <= 0.001) {
            mission.phase = MissionPhase.AT_OBJECTIVE;
            // Spawn entity if needed
            if (!mission.targetEntityId) {
              const entity = spawnMissionEntity(mission, gameState);
              if (entity) mission.targetEntityId = entity.id;
            }
            return { type: 'station-mission-phase', mission, phase: MissionPhase.AT_OBJECTIVE,
              message: `Arrived at objective — scan area` };
          }
        }
        mission.phase = MissionPhase.IN_TRANSIT;
      }
      break;
    }

    case StationMissionType.SURVEY: {
      // Stay in zone and accumulate scan time
      if (mission.phase === MissionPhase.ACCEPTED || mission.phase === MissionPhase.IN_TRANSIT) {
        if (mission.targetPosition) {
          const dx = shipPos.x - mission.targetPosition.x;
          const dy = shipPos.y - mission.targetPosition.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist <= 0.001) {
            mission.phase = MissionPhase.AT_OBJECTIVE;
            return { type: 'station-mission-phase', mission, phase: MissionPhase.AT_OBJECTIVE,
              message: `In survey zone — scanning (${mission._scanAccumulated || 0}/${mission.scanDuration} min)` };
          }
        }
        mission.phase = MissionPhase.IN_TRANSIT;
      }
      if (mission.phase === MissionPhase.AT_OBJECTIVE) {
        // Accumulate scan time while in zone
        if (mission.targetPosition) {
          const dx = shipPos.x - mission.targetPosition.x;
          const dy = shipPos.y - mission.targetPosition.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist <= 0.001) {
            mission._scanAccumulated = (mission._scanAccumulated || 0) + 1;
            if (mission._scanAccumulated >= mission.scanDuration) {
              mission.phase = MissionPhase.OBJECTIVE_COMPLETE;
              return { type: 'station-mission-phase', mission, phase: MissionPhase.OBJECTIVE_COMPLETE,
                message: `Survey complete — return to ${getStationName(mission, gameState)}` };
            }
          } else {
            // Left the zone — back to in-transit
            mission.phase = MissionPhase.IN_TRANSIT;
            return { type: 'station-mission-phase', mission, phase: MissionPhase.IN_TRANSIT,
              message: 'Left survey zone — return to continue scanning' };
          }
        }
      }
      break;
    }
  }

  // Check if returning to station (for missions that require turn-in)
  if (mission.phase === MissionPhase.OBJECTIVE_COMPLETE || mission.phase === MissionPhase.RETURNING) {
    const station = (gameState.entities || []).find(e => e.id === mission.stationId);
    if (station) {
      const dist = entityDistanceAU(shipPos, station.position);
      if (dist <= LONG_SCANNER_RANGE_AU) {
        mission.phase = MissionPhase.RETURNING;
        // Completion happens via hail — handled in app.js
      }
    }
  }

  return null;
}

// ---- ENTITY SPAWNING FOR FIELD MISSIONS ----

function spawnMissionEntity(mission, gameState) {
  const pos = mission.targetPosition;
  if (!pos) return null;

  // Compute orbital velocity at this position
  const AU_M_VAL = 149_597_870_700;
  const GM_SUN = 1.327124e20;
  const r_m = Math.sqrt(pos.x * pos.x + pos.y * pos.y) * AU_M_VAL;
  const orbSpeed = Math.sqrt(GM_SUN / r_m);
  const orbAngle = Math.atan2(pos.y, pos.x) + Math.PI / 2;

  let entity;

  switch (mission.type) {
    case StationMissionType.INVESTIGATE_DISAPPEARANCE: {
      const isAlive = mission._outcome === 'alive';
      entity = createEntity({
        id: `inv-${mission.id}`,
        name: mission._missingShipName,
        type: EntityType.SHIP,
        state: isAlive ? EntityState.DRIFTING : EntityState.DRIFTING,
        position: { ...pos },
        velocity: { vx: Math.cos(orbAngle) * orbSpeed, vy: Math.sin(orbAngle) * orbSpeed },
        faction: 'Belter',
        shipClass: mission._missingShipClass || 'Unknown',
        mass: randInt(20000, 100000),
        transponderActive: mission._outcome !== 'debris',
        sosActive: isAlive,
      });
      break;
    }

    case StationMissionType.SALVAGE: {
      entity = createEntity({
        id: `salvage-${mission.id}`,
        name: `Derelict ${randInt(100, 999)}`,
        type: EntityType.SHIP,
        state: EntityState.DRIFTING,
        position: { ...pos },
        velocity: { vx: Math.cos(orbAngle) * orbSpeed, vy: Math.sin(orbAngle) * orbSpeed },
        faction: 'independent',
        shipClass: pick(['Wreck', 'Hulk', 'Derelict']),
        mass: randInt(30000, 150000),
        transponderActive: false,
      });
      break;
    }

    case StationMissionType.MEDICAL_EVAC: {
      entity = createEntity({
        id: `medevac-${mission.id}`,
        name: mission._evacShipName,
        type: EntityType.SHIP,
        state: EntityState.DRIFTING,
        position: { ...pos },
        velocity: { vx: Math.cos(orbAngle) * orbSpeed, vy: Math.sin(orbAngle) * orbSpeed },
        faction: 'Belter',
        shipClass: mission._evacShipClass || 'Freighter',
        mass: randInt(30000, 100000),
        sosActive: true,
        transponderActive: true,
      });
      break;
    }
  }

  if (entity) {
    gameState.entities.push(entity);
  }
  return entity;
}

// ---- ACCEPT / COMPLETE ----

/**
 * Accept a mission from a station's board.
 */
export function acceptStationMission(stationId, missionId, gameState) {
  const station = (gameState.entities || []).find(e => e.id === stationId);
  if (!station || !station._missionBoard) return null;

  const board = station._missionBoard;
  const idx = board.missions.findIndex(m => m.id === missionId);
  if (idx < 0) return null;

  const mission = board.missions[idx];
  if (mission.phase !== MissionPhase.AVAILABLE) return null;

  // For fuel resupply: deduct fuel from ship
  if (mission.type === StationMissionType.FUEL_RESUPPLY && mission.fuelRequired) {
    const fuel = gameState.resources.fuel;
    if (fuel.current < mission.fuelRequired) return null; // not enough fuel
    fuel.current -= mission.fuelRequired;
  }

  mission.phase = MissionPhase.ACCEPTED;
  mission.acceptedAt = gameMinute(gameState);

  // Move from board to active list
  board.missions.splice(idx, 1);
  activeMissions.push(mission);

  return mission;
}

/**
 * Complete a station mission (turn in at station via hail).
 * Returns { success, narrative, rewards }
 */
export function completeStationMission(missionId, gameState) {
  const mission = activeMissions.find(m => m.id === missionId);
  if (!mission) return { success: false, narrative: 'No such mission.' };

  // Must be at the right phase
  const canComplete =
    // Delivery missions: at destination
    (mission.destination && mission.phase === MissionPhase.AT_OBJECTIVE) ||
    // Field missions (investigate, salvage, medevac): objective complete + returning
    (mission.phase === MissionPhase.OBJECTIVE_COMPLETE || mission.phase === MissionPhase.RETURNING) ||
    // Survey: objective complete
    (mission.phase === MissionPhase.OBJECTIVE_COMPLETE);

  if (!canComplete) {
    return { success: false, narrative: 'Mission objective not yet complete.' };
  }

  // Apply rewards
  const res = gameState.resources;
  for (const [key, amount] of Object.entries(mission.reward)) {
    if (res[key]) {
      if (res[key].max === Infinity) {
        res[key].current += amount;
      } else {
        res[key].current = Math.min(res[key].max, res[key].current + amount);
      }
    }
  }

  mission.phase = MissionPhase.COMPLETE;
  mission.completedAt = gameMinute(gameState);

  // Generate completion narrative
  const narrative = getCompletionNarrative(mission);

  return { success: true, narrative, rewards: mission.reward };
}

// ---- NARRATIVES ----

function getCompletionNarrative(mission) {
  switch (mission.type) {
    case StationMissionType.CARGO_HAUL:
      return `Cargo delivered to ${mission.destinationName}. Dock workers begin unloading the ${mission.cargo?.type || 'cargo'}. Payment transferred.`;
    case StationMissionType.PASSENGER_TRANSPORT:
      return `Passengers disembark at ${mission.destinationName}.${mission._isVIP ? ' The VIP sends their regards — and a generous bonus.' : ' Another safe transit.'} Payment transferred.`;
    case StationMissionType.FUEL_RESUPPLY:
      return `Fuel transfer complete. ${mission.destinationName} ops confirms receipt of ${mission.fuelRequired?.toLocaleString() || ''} kg of reaction mass. Compensation transferred.`;
    case StationMissionType.INVESTIGATE_DISAPPEARANCE:
      return `Investigation report filed. ${mission._outcome === 'alive' ? 'The crew was found alive — rescue coordination underway.' : mission._outcome === 'derelict' ? 'Ship found drifting, no survivors. The station will send a recovery team.' : 'Only debris remains. The station records the loss.'} Payment transferred.`;
    case StationMissionType.SALVAGE:
      return `Salvage operation complete. ${mission._salvageType} recovered and delivered. Standard salvage rights applied — payment transferred.`;
    case StationMissionType.SURVEY:
      return `Survey data uploaded to station archives. Sector ${mission._sector} mapped for ${mission._surveyTarget}. Payment transferred.`;
    case StationMissionType.MEDICAL_EVAC:
      return `Patients transferred to station medical. ${mission.patientCount} souls delivered for treatment. Medical supplies restocked as compensation.`;
    default:
      return 'Mission complete. Payment transferred.';
  }
}

// ---- QUERIES ----

export function getActiveStationMissions() {
  return activeMissions.filter(m => m.phase !== MissionPhase.COMPLETE && m.phase !== MissionPhase.FAILED);
}

export function getAllStationMissions() {
  return activeMissions;
}

export function getStationBoard(stationId) {
  // search active missions for any that belong to this station (already accepted)
  return activeMissions.filter(m => m.stationId === stationId && m.phase !== MissionPhase.COMPLETE && m.phase !== MissionPhase.FAILED);
}

function getStationName(mission, gameState) {
  const station = (gameState.entities || []).find(e => e.id === mission.stationId);
  return station?.name || 'station';
}

// ---- SERIALIZATION ----

export function serializeStationMissions() {
  return {
    activeMissions: JSON.parse(JSON.stringify(activeMissions)),
    nextStationMissionId,
  };
}

export function deserializeStationMissions(data) {
  if (!data) return;
  activeMissions = data.activeMissions || [];
  nextStationMissionId = data.nextStationMissionId || 1;
}

export function initStationMissions() {
  activeMissions = [];
  nextStationMissionId = 1;
}
